import{_ as a,o as r,c as t,S as i}from"./chunks/framework.DZlzLDBr.js";const p=JSON.parse('{"title":"Card Browser","description":"","frontmatter":{},"headers":[],"relativePath":"Card-Browser.md","filePath":"Card-Browser.md","lastUpdated":null}'),o={name:"Card-Browser.md"};function l(s,e,n,d,c,u){return r(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="card-browser" tabindex="-1">Card Browser <a class="header-anchor" href="#card-browser" aria-label="Permalink to &quot;Card Browser&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Card Browser is a table view of all cards in your vault. Use it to find, filter, edit, and manage cards in bulk.</p><h2 id="main-controls" tabindex="-1">Main controls <a class="header-anchor" href="#main-controls" aria-label="Permalink to &quot;Main controls&quot;">​</a></h2><ul><li><strong>Sort</strong>: click a column header to sort; click again to reverse order.</li><li><strong>Search</strong>: text search across card fields.</li><li><strong>Filters</strong>: <ul><li>Type (Basic, Cloze, MCQ, IO, Ordered)</li><li>Stage (New, Learning, Review, Relearning, Suspended, Buried)</li><li>Due status (Due, Today, Later)</li></ul></li><li><strong>Reset</strong>: clears filters back to default.</li></ul><h2 id="edit-and-bulk-actions" tabindex="-1">Edit and bulk actions <a class="header-anchor" href="#edit-and-bulk-actions" aria-label="Permalink to &quot;Edit and bulk actions&quot;">​</a></h2><ul><li>Select one or more rows.</li><li>Use actions to edit, suspend/unsuspend, or clear selection.</li><li>Changes from edit actions appear in the table immediately.</li></ul><p>See <a href="./Suspending-Cards">Suspending Cards</a> for suspend behavior.</p><h2 id="pagination-and-layout" tabindex="-1">Pagination and layout <a class="header-anchor" href="#pagination-and-layout" aria-label="Permalink to &quot;Pagination and layout&quot;">​</a></h2><ul><li>Move through pages using controls at the bottom.</li><li>Change rows per page from the page-size selector.</li><li>Use <strong>Expand table / Collapse table</strong> to switch width.</li></ul><h2 id="edge-cases" tabindex="-1">Edge cases <a class="header-anchor" href="#edge-cases" aria-label="Permalink to &quot;Edge cases&quot;">​</a></h2><ul><li>If no rows appear, check active filters and search text first.</li><li>Some columns may be hidden if column visibility was changed.</li><li>Bulk actions only apply to selected rows.</li></ul>',13)])])}const g=a(o,[["render",l]]);export{p as __pageData,g as default};
